1288	    uint8_t** dbuffer_list;
1289	    hipIpcMemHandle_t buffer_ipc_handle;
1290	    std::vector<hipIpcMemHandle_t> all_buffer_ipc_handles;
1291	    std::vector<uint8_t*> buffer_list;
1292	    uint32_t data_offset;
1293	
1294	    DeviceComms() : initialized(false), world_size(1), rank(0) {}
