    }                                                                                       \
    else                                                                                    \
    {                                                                                       \
        throw std::runtime_error("INT3 quick all-reduce is only supported for world_size "  \
                                 "== 2 (TP2); use INT4/NONE for larger world sizes.");      \
    }

