input.new_string:
    __device__ static void run(T const* __restrict__ input,
                               T const* __restrict__ residual_inp,
                               T* __restrict__ residual_out,
                               T* __restrict__ output,
                               T const* __restrict__ weight,
                               float eps,
                               uint32_t const N,
                               uint32_t const hidden_dim,
                               int const block,
                               int const rank,
                               uint8_t** __restrict__ buffer_list,
                               uint32_t const data_offset,
                               uint32_t flag_color,
                               int64_t data_size_per_phase)
    {
        // Topology
        int thread           = threadIdx.x + threadIdx.y * kWavefront;
        uint8_t* rank_buffer = buffer_list[rank];
        Codec codec(thread, rank);
        int block_id = blockIdx.x;
        uint8_t* buffer_ptr[Codec::kWorldSize];
        for(int i = 0; i < Codec::kWorldSize; ++i)
        {
            buffer_ptr[i] = buffer_list[i];
        }

        // ======================================================================
        // Phase 1: All-reduce (same communication pattern as AllReduceTwoshot)
        // ======================================================================

        // Read input into registers
        int32x4_t tA[kAtoms];
        BufferResource src_buffer(const_cast<T*>(input), N * sizeof(T));
        uint32_t src_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            tA[i] = buffer_load_dwordx4(src_buffer.descriptor, src_offset, 0, 0);
            src_offset += kAtomStride * sizeof(int32x4_t);
            if constexpr(std::is_same<CommT, __hip_bfloat16>::value && std::is_same<T, half>::value)
            {
                const nv_bfloat162* bf_buf = reinterpret_cast<const nv_bfloat162*>(&tA[i]);
                half2 half_buf[4];
#pragma unroll
                for(int j = 0; j < 4; ++j)
                {
                    float2 f    = __bfloat1622float2(bf_buf[j]);
                    half_buf[j] = __float22half2_rn(f);
                }
                tA[i] = *reinterpret_cast<const int32x4_t*>(half_buf);
            }
        }

        // Phase-1A: Write segment data into communication buffer
        uint32_t comm_data0_offset = data_offset + block_id * Codec::kTransmittedTileSize;
        uint32_t comm_data1_offset = data_size_per_phase + comm_data0_offset;
        uint32_t comm_flags0_offset = block_id * (Codec::kWorldSize * sizeof(uint32_t));
        uint32_t comm_flags1_offset = (data_offset / 2) + comm_flags0_offset;

        for(int r = 0; r < Codec::kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data0_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, &tA[r * Codec::kRankAtoms]);
        }

        __syncthreads();
        if(thread < Codec::kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags0_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // Phase-1B: Reduce the segment data from communication buffers
        int32x4_t tR[Codec::kRankAtoms] = {};
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data0_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags0_offset);

            for(int r = 0; r < Codec::kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, tA);

                for(int i = 0; i < Codec::kRankAtoms; i++)
                {
                    packed_assign_add<CommT>(&tR[i], &tA[i]);
                }
            }
        }

        // Phase-2A: Write the reduced segment to every other rank
        for(int r = 0; r < Codec::kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data1_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, tR);
        }

        __syncthreads();
        if(thread < Codec::kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags1_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // Phase-2B: Read the gather segments from rank's communication buffer
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data1_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags1_offset);

            for(int r = 0; r < Codec::kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, &tA[r * Codec::kRankAtoms]);
            }
        }

        // ======================================================================
        // Epilogue: Add residual and apply RMSNorm
        // ======================================================================

        // Load residual_inp and weight into registers as we iterate
        // Process one row (hidden_dim elements) at a time
        uint32_t dst_offset = block * kTileSize + thread * sizeof(int32x4_t);
        uint32_t residual_offset = block * kTileSize + thread * sizeof(int32x4_t);
        uint32_t weight_offset = 0;

        // Number of rows (tokens) in this tile
        uint32_t rows_per_tile = kTileSize / (hidden_dim * sizeof(T));
        uint32_t elem_per_atom = kElemsPerAtom;

        // Process each row
        for(uint32_t row_idx = 0; row_idx < rows_per_tile; row_idx++)
        {
            // Step 1: Add residual to all-reduced value
            for(int i = 0; i < kAtoms; i++)
            {
                int32x4_t residual_vals;
                BufferResource res_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
                uint32_t cur_residual_offset = residual_offset + i * kAtomStride * sizeof(int32x4_t);
                residual_vals = buffer_load_dwordx4(res_buffer.descriptor, cur_residual_offset, 0, 0);

                packed_assign_add<T>(&tA[i], &residual_vals);
            }

            // Step 2: Compute RMSNorm denominator (rsqrt(mean(x^2) + eps))
            // Compute sum of squares across the row
            float sum_sq = 0.0f;

            for(int i = 0; i < kAtoms; i++)
            {
                T const* vals = reinterpret_cast<T const*>(&tA[i]);
                for(int j = 0; j < elem_per_atom; j++)
                {
                    float v = qr_to_float<T>(vals[j]);
                    sum_sq += v * v;
                }
            }

            // Reduce sum_sq across all threads handling this row
            // Each thread processes elem_per_atom * kAtoms = 128 elements per 256 threads
            // So we need to reduce within threads that touch the same row

            // Use warp shuffle to reduce
            for(int i = 1; i < 32; i <<= 1)
            {
                sum_sq += __shfl_down(sum_sq, i);
            }

            // Broadcast from lane 0 of each warp
            int warp_id = threadIdx.x / 32;
            int lane_id = threadIdx.x % 32;

            __shared__ float shared_sum_sq[8];
            if(lane_id == 0)
            {
                shared_sum_sq[warp_id] = sum_sq;
            }
            __syncthreads();

            float total_sum_sq = 0.0f;
            if(threadIdx.x < 8)
            {
                total_sum_sq = shared_sum_sq[threadIdx.x];
            }

            // Final reduction across all 8 values
            for(int i = 1; i < 8; i <<= 1)
            {
                total_sum_sq += __shfl_down(total_sum_sq, i);
            }

            total_sum_sq = __shfl(total_sum_sq, 0);

            // Compute denominator: rsqrt(mean(x^2) + eps)
            float denom = rsqrtf(total_sum_sq / (float)hidden_dim + eps);

            // Step 3: Write residual_out and apply normalization + weight
            for(int i = 0; i < kAtoms; i++)
            {
                // Write pre-normalized residual sum to residual_out
                BufferResource res_out_buffer(residual_out, N * sizeof(T));
                uint32_t cur_res_out_offset = residual_offset + i * kAtomStride * sizeof(int32x4_t);
                buffer_store_dwordx4(tA[i], res_out_buffer.descriptor, cur_res_out_offset, 0, 0);

                // Load weight
                int32x4_t weight_vals;
                BufferResource weight_buffer(const_cast<T*>(weight), hidden_dim * sizeof(T));
                uint32_t cur_weight_offset = weight_offset + i * kAtomStride * sizeof(int32x4_t);
                weight_vals = buffer_load_dwordx4(weight_buffer.descriptor, cur_weight_offset, 0, 0);

                // Normalize and apply weight
                T const* res_vals = reinterpret_cast<T const*>(&tA[i]);
                T const* w_vals = reinterpret_cast<T const*>(&weight_vals);
                T* out_vals = reinterpret_cast<T*>(&tA[i]);

                for(int j = 0; j < elem_per_atom; j++)
                {
                    float v = qr_to_float<T>(res_vals[j]);
                    float w = qr_to_float<T>(w_vals[j]);
                    float normalized = v * denom * w;
                    out_vals[j] = qr_from_float<T>(normalized);
                }
            }

            // Write output
            BufferResource out_buffer(output, N * sizeof(T));
            for(int i = 0; i < kAtoms; i++)
            {
                uint32_t cur_dst_offset = dst_offset + i * kAtomStride * sizeof(int32x4_t);
                buffer_store_dwordx4(tA[i], out_buffer.descriptor, cur_dst_offset, 0, 0);
            }

            // Move to next row
            dst_offset += rows_per_tile > 0 ? hidden_dim * sizeof(T) : 0;
            residual_offset += rows_per_tile > 0 ? hidden_dim * sizeof(T) : 0;
            weight_offset = 0;  // Weight repeats for each row
        }
    }

