        uint32_t num_rows_in_tile = kTileSize / row_bytes;

        BufferResource res_in_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
        BufferResource res_out_buffer(residual_out, N * sizeof(T));
        BufferResource out_buffer(output, N * sizeof(T));
        BufferResource weight_buffer(const_cast<T*>(weight), hidden_dim * sizeof(T));

        // Allocate shared memory for row sum of squares
        // num_rows_in_tile = kTileSize / (hidden_dim * sizeof(T))
        // Max size needed: (32KiB / (4096 * 2)) = 4 rows when hidden_dim=4096, so max 4 floats
        __shared__ float row_sum_sq[256];  // Use fixed size; more than enough
        for(uint32_t i = threadIdx.x + threadIdx.y * kWavefront; i < num_rows_in_tile;
            i += kBlockSize)
        {
            row_sum_sq[i] = 0.0f;
        }
        __syncthreads();

        // First pass: compute residual_inp + input and accumulate sum of squares per row
        {
            uint32_t cur_offset = residual_offset;
            for(int atom_idx = 0; atom_idx < kAtoms; atom_idx++)
            {
                // Load residual for this atom
                int32x4_t residual_vals =
                    buffer_load_dwordx4(res_in_buffer.descriptor, cur_offset, 0, 0);

                // Add to all-reduced
                packed_assign_add<T>(&tA[atom_idx], &residual_vals);

                // Determine row and accumulate sum of squares
                uint32_t offset_in_block = cur_offset - (block * kTileSize);
                uint32_t row_idx = offset_in_block / row_bytes;

                // Accumulate sum of squares for this row
                T const* atom_vals = reinterpret_cast<T const*>(&tA[atom_idx]);
                for(int j = 0; j < elems_per_atom; j++)
                {
                    float v = qr_to_float<T>(atom_vals[j]);
                    // Use atomic add to safely accumulate
                    atomicAdd(&row_sum_sq[row_idx], v * v);
                }

                cur_offset += kAtomStride * sizeof(int32x4_t);
            }
        }
        __syncthreads();

        // Second pass: write residual_out and output with normalization
        {
            uint32_t cur_dst_offset = dst_offset;
            uint32_t cur_residual_offset = residual_offset;

            for(int atom_idx = 0; atom_idx < kAtoms; atom_idx++)
            {
                uint32_t offset_in_block = cur_residual_offset - (block * kTileSize);
                uint32_t row_idx = offset_in_block / row_bytes;
                uint32_t col_offset = offset_in_block % row_bytes;

                // Compute denominator from row sum
                float denom = rsqrtf(row_sum_sq[row_idx] / (float)hidden_dim + eps);

                // Write residual_out
                buffer_store_dwordx4(tA[atom_idx], res_out_buffer.descriptor,
                                     cur_residual_offset, 0, 0);

                // Load weight
                int32x4_t weight_vals =
                    buffer_load_dwordx4(weight_buffer.descriptor, col_offset, 0, 0);

